+fn format_speed(bytes: u64, duration_ms: u64) -> String {
+    if duration_ms == 0 || bytes == 0 {
+        return "--".to_string();
+    }
+    let secs = duration_ms as f64 / 1000.0;
+    if secs <= 0.0 {
+        return "--".to_string();
+    }
+    let per_sec = (bytes as f64 / secs).round() as u64;
+    format!("{}/s", format_bytes(per_sec))
+}
